const t={hostControl:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Verwalte den Linux-Host des Druckers — prüfe seinen Zustand und den des Betriebssystems. Dienste, Datenträger-Bereinigung und Systemeinstellungen folgen in späteren Phasen."}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"Was ist das?"}},body:{t:0,b:{t:2,i:[{t:3}],s:"FilaMind läuft auf dem kleinen Linux-Computer des Druckers (dem Host). Dieses Panel liest dessen Live-Zustand und Betriebssystem-Status, damit du Probleme erkennst — eine überhitzte CPU, eine volle Festplatte, eine nicht synchronisierte Uhr — ohne ein Terminal zu öffnen."}},step1:{t:0,b:{t:2,i:[{t:3}],s:"Lies die Karten für CPU-Temperatur, Speicher, Datenträger und Netzwerk auf einen Blick."}},step2:{t:0,b:{t:2,i:[{t:3}],s:"Beobachte die Tabelle der Top-Prozesse, um zu sehen, was die CPU gerade auslastet."}},step3:{t:0,b:{t:2,i:[{t:3}],s:"Lass die automatische Aktualisierung für eine Live-Ansicht an, oder schalte sie aus und aktualisiere manuell."}},topics:{glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Hier verwendete Begriffe"}}},monitor:{title:{t:0,b:{t:2,i:[{t:3}],s:"Den Monitor lesen"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Alles hier ist schreibgeschützt. Balken werden ab 75 % bernsteinfarben und ab 90 % rot. Die CPU-Temperatur wird bei 70 °C bernsteinfarben und bei 80 °C rot. Die Drosselungs-Warnung erscheint nur auf Boards, die sie melden (hauptsächlich Raspberry Pi)."}}}},glossary:{host:{term:{t:0,b:{t:2,i:[{t:3}],s:"Host"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Der kleine Linux-Computer (z. B. ein Raspberry Pi oder BTT CB1), der Klipper, Moonraker und FilaMind ausführt — getrennt von den Mikrocontrollern des Druckers."}}},load:{term:{t:0,b:{t:2,i:[{t:3}],s:"Lastdurchschnitt"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Wie viele Prozesse auf Ausführung warteten, gemittelt über 1 / 5 / 15 Minuten. Grob: ein Wert nahe der Kernzahl bedeutet, die CPU ist beschäftigt; deutlich darüber bedeutet Überlastung."}}},swap:{term:{t:0,b:{t:2,i:[{t:3}],s:"Swap"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Festplattenspeicher, der als Überlauf genutzt wird, wenn der RAM voll ist. Starke Swap-Nutzung verlangsamt den Host — ein Zeichen für Speichermangel."}}},throttle:{term:{t:0,b:{t:2,i:[{t:3}],s:"Drosselung"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Wenn das Board die Geschwindigkeit reduziert, um sich selbst zu schützen — meist wegen einer schwachen Stromversorgung (Unterspannung) oder Überhitzung. Wird hauptsächlich beim Raspberry Pi gemeldet."}}},ntp:{term:{t:0,b:{t:2,i:[{t:3}],s:"NTP / Uhr-Synchronisation"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Das Network Time Protocol hält die Host-Uhr genau. Eine nicht synchronisierte Uhr kann Zeitraffer, Protokolle und TLS-Zertifikate stören."}}},locale:{term:{t:0,b:{t:2,i:[{t:3}],s:"Locale"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Die Sprach- und Tastaturlayout-Einstellungen des Hosts, die das Betriebssystem für Text, Datumsangaben und das Konsolen-Tastaturlayout nutzt."}}}}},monitor:{refresh:{t:0,b:{t:2,i:[{t:3}],s:"Aktualisieren"}},autoRefresh:{t:0,b:{t:2,i:[{t:3}],s:"Auto-Aktualisierung"}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Host-Status wird gelesen…"}},host:{t:0,b:{t:2,i:[{t:3}],s:"Host"}},hostname:{t:0,b:{t:2,i:[{t:3}],s:"Hostname"}},distro:{t:0,b:{t:2,i:[{t:3}],s:"Betriebssystem"}},kernel:{t:0,b:{t:2,i:[{t:3}],s:"Kernel"}},uptime:{t:0,b:{t:2,i:[{t:3}],s:"Laufzeit"}},cpu:{t:0,b:{t:2,i:[{t:3}],s:"CPU"}},temp:{t:0,b:{t:2,i:[{t:3}],s:"Temperatur"}},load:{t:0,b:{t:2,i:[{t:3}],s:"Last (1·5·15 Min)"}},cores:{t:0,b:{t:2,i:[{t:3}],s:"Kerne"}},throttled:{t:0,b:{t:2,i:[{t:3}],s:"Gedrosselt"}},memory:{t:0,b:{t:2,i:[{t:3}],s:"Speicher"}},ram:{t:0,b:{t:2,i:[{t:3}],s:"RAM"}},swap:{t:0,b:{t:2,i:[{t:3}],s:"Swap"}},disk:{t:0,b:{t:2,i:[{t:3}],s:"Datenträger"}},network:{t:0,b:{t:2,i:[{t:3}],s:"Netzwerk"}},iface:{t:0,b:{t:2,i:[{t:3}],s:"Schnittstelle"}},ip:{t:0,b:{t:2,i:[{t:3}],s:"IP-Adresse"}},ssid:{t:0,b:{t:2,i:[{t:3}],s:"WLAN"}},signal:{t:0,b:{t:2,i:[{t:3}],s:"Signal"}},timeLocale:{t:0,b:{t:2,i:[{t:3}],s:"Zeit & Locale"}},timezone:{t:0,b:{t:2,i:[{t:3}],s:"Zeitzone"}},ntp:{t:0,b:{t:2,i:[{t:3}],s:"Uhr-Synchronisation"}},synced:{t:0,b:{t:2,i:[{t:3}],s:"Synchronisiert"}},syncing:{t:0,b:{t:2,i:[{t:3}],s:"Wird synchronisiert…"}},ntpOff:{t:0,b:{t:2,i:[{t:3}],s:"Aus"}},language:{t:0,b:{t:2,i:[{t:3}],s:"Sprache"}},keymap:{t:0,b:{t:2,i:[{t:3}],s:"Tastaturlayout"}},topProcesses:{t:0,b:{t:2,i:[{t:3}],s:"Top-Prozesse"}},command:{t:0,b:{t:2,i:[{t:3}],s:"Befehl"}},cpuPct:{t:0,b:{t:2,i:[{t:3}],s:"CPU %"}},memPct:{t:0,b:{t:2,i:[{t:3}],s:"RAM %"}},pid:{t:0,b:{t:2,i:[{t:3}],s:"PID"}}}}};export{t as default};
